require_once dirname(__DIR__) . '/includes/site-shell.php'; ensure_nexshelfy_serious_schema(); csrf_token(); ?><!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Become a Creator · NexShelfy</title><link rel="icon" href="/favicon.svg" type="image/svg+xml"><link rel="stylesheet" href="/assets/content-platform.css?v=20260711-unified-admin-theme-v4"><link rel="stylesheet" href="/assets/nexshelfy-app.css?v=20260711-unified-admin-theme-v4"><link rel="stylesheet" href="/assets/nexshelfy-shop-fixes.css?v=20260717-final-ui-2"></head><body class="cp-page ns-unified-page"><?php ns_site_header('creators'); ?><main class="cp-shell"><section class="ns-split-hero"><div class="ns-split-copy"><div class="cp-kicker">Creator application</div><h1>Share useful resources with the NexShelfy audience.</h1><p>Fill this internal application form. It works like a Google Form, but saves directly inside your admin Creator Apps page.</p></div><form class="ns-creator-application-form ns-form-panel"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><div class="ns-grid-2"><label>Name<input name="name" required></label><label>Email<input name="email" type="email" required></label><label>Age<input name="age"></label><label>Gender<input name="gender"></label></div><label>Qualifications<input name="qualification" placeholder="Education, skills, experience"></label><label>Why do you want to become a creator?<textarea name="reason" rows="5" required></textarea></label><label>How can you contribute to NexShelfy?<textarea name="contribution" rows="5" required></textarea></label><button class="ns-btn" type="submit">Submit application</button><div class="ns-inline-message" role="status"></div></form></section></main><script src="/assets/nexshelfy-app.js?v=20260711-unified-admin-theme-v4"></script><script>document.querySelector('.ns-creator-application-form')?.addEventListener('submit',async e=>{e.preventDefault();const f=e.currentTarget,msg=f.querySelector('.ns-inline-message');try{const r=await fetch('/api/creator-application.php',{method:'POST',credentials:'include',headers:{'Content-Type':'application/json','X-CSRF-Token':f.csrf.value},body:JSON.stringify(Object.fromEntries(new FormData(f)))});const j=await r.json();msg.textContent=j.message||'Application submitted successfully.';msg.classList.toggle('success',!!j.ok);if(j.ok)f.reset();}catch(err){msg.textContent='Could not submit. Please try again.';}});</script></body></html>
